# qp2/image_viewer/plugins/dials/submit_dials_dataset_job.py
import json
import os
import shlex
import time
from pathlib import Path

from PyQt5.QtCore import QRunnable, pyqtSignal, QObject

from qp2.image_viewer.utils.run_job import run_command, is_sbatch_available
from qp2.log.logging_config import get_logger
from qp2.xio.proc_utils import determine_proc_base_dir
from qp2.config.programs import ProgramConfig

logger = get_logger(__name__)

# Template for the shell script that will run on the cluster
dials_run_script_template = """#!/bin/bash
# Autogenerated script for DIALS SSX processing
echo "--- Starting DIALS SSX processing on $(date) at $(hostname) ---"

# We will check exit codes manually instead of using 'set -e'
# This ensures the final parsing step always runs.
DIALS_ERROR=0

run_dials() {{
    echo "Executing: $@"
    "$@"
    local exit_code=$?
    if [ $exit_code -ne 0 ]; then
        echo "DIALS command failed with exit code $exit_code: $@" >&2
        DIALS_ERROR=1
    fi
    return $exit_code
}}

# --- DIALS Pipeline ---
# The pipeline will stop if a crucial step fails.
(
    run_dials dials.import {master_file} && \\
    run_dials dials.find_spots imported.expt nproc={nproc} {d_min_param} && \\
    run_dials dials.ssx_index imported.expt strong.refl max_lattices=2 nproc={nproc} {unit_cell_param} {space_group_param} {extra_options} && \\
    run_dials dials.ssx_integrate indexed.expt indexed.refl nproc={nproc}
) || echo "A DIALS command failed. Proceeding to parsing stage to report error."


echo "--- DIALS commands finished. Parsing results... ---"

# --- Result Parsing (ALWAYS RUNS) ---
# Use dials.python to ensure the correct environment.
dials.python {parser_script_path} \\
    --proc_dir "{proc_dir}" \\
    --redis_key "{redis_key}" \\
    --status_key "{status_key}" \\
    --redis_host "{redis_host}" \\
    --redis_port "{redis_port}"

echo "--- Processing complete. ---"
"""


class DialsJobSignals(QObject):
    result = pyqtSignal(str, str, str)
    error = pyqtSignal(str, str)


class DialsProcessDatasetWorker(QRunnable):
    """Generates a self-contained shell script and submits it for an ENTIRE dataset."""

    def __init__(self, master_file, metadata, redis_conn, redis_key_prefix, **kwargs):
        super().__init__()
        self.master_file = master_file
        self.metadata = metadata
        self.redis_conn = redis_conn
        self.redis_key_prefix = redis_key_prefix
        self.kwargs = kwargs
        self.signals = DialsJobSignals()

    def run(self):
        try:
            # --- Gatekeeper and Directory Setup ---
            if not self.redis_conn:
                return
            results_key = f"{self.redis_key_prefix}:{self.master_file}"
            status_key = f"{results_key}:status"
            initial_status = {"status": "SUBMITTED", "timestamp": time.time()}
            if not self.redis_conn.set(
                status_key, json.dumps(initial_status), ex=7 * 24 * 3600, nx=True
            ):
                logger.info(
                    f"DIALS job for {os.path.basename(self.master_file)} frame {self.start_frame} already submitted. Skipping."
                )
                return

            if self.kwargs.get("output_proc_dir"):
                proc_dir = Path(self.kwargs.get("output_proc_dir"))
            else:
                # Use common root logic
                user_root = self.kwargs.get("processing_common_proc_dir_root") or self.kwargs.get("dials_ssx_proc_dir_root")
                proc_base = determine_proc_base_dir(user_root, self.master_file)
                
                master_basename = os.path.splitext(os.path.basename(self.master_file))[0]
                proc_dir = proc_base / "dials_ssx" / master_basename

            proc_dir.mkdir(parents=True, exist_ok=True)
            self.redis_conn.hset(results_key, "_proc_dir", str(proc_dir))

            # --- Generate the execution script ---
            parser_script_path = os.path.join(
                os.path.dirname(__file__), "parse_dials.py"
            )
            
            # Cluster-safe path resolution
            cluster_root = os.environ.get("CLUSTER_PROJECT_ROOT")
            if cluster_root:
                relative_script_path = "image_viewer/plugins/dials_ssx/parse_dials.py"
                parser_script_path = os.path.join(cluster_root, relative_script_path)
            d_min_param = (
                f"d_min={self.kwargs.get('dials_d_min')}"
                if self.kwargs.get("dials_d_min")
                else ""
            )
            space_group_param = (
                f"space_group={self.kwargs.get('dials_space_group')}"
                if self.kwargs.get("dials_space_group")
                else ""
            )
            unit_cell_param = (
                f"unit_cell='{self.kwargs.get('dials_unit_cell')}'"
                if self.kwargs.get("dials_unit_cell")
                else ""
            )
            extra_options = " ".join(
                shlex.split(self.kwargs.get("dials_extra_options", ""))
            )
            host = self.redis_conn.connection_pool.connection_kwargs.get("host")
            port = self.redis_conn.connection_pool.connection_kwargs.get("port")

            script_content = dials_run_script_template.format(
                master_file=self.master_file,
                nproc=self.kwargs.get("dials_nproc", 8),
                d_min_param=d_min_param,
                space_group_param=space_group_param,
                unit_cell_param=unit_cell_param,
                extra_options=extra_options,
                parser_script_path=parser_script_path,
                proc_dir=str(proc_dir),
                redis_key=results_key,
                status_key=status_key,
                redis_host=host,
                redis_port=port,
            )

            job_name = f"dials_ssx_{master_basename}"
            # This is the path where the generated script will be saved by this worker.
            execution_script_path = proc_dir / f"{job_name}_runner.sh"
            with open(execution_script_path, "w") as f:
                f.write(script_content)
            os.chmod(execution_script_path, 0o755)  # Make it executable

            # --- Submit the generated script for execution ---
            run_method = "slurm" if is_sbatch_available() else "shell"

            run_command(
                cmd=[
                    str(execution_script_path)
                ],  # The command is now just the path to our script
                pre_command=ProgramConfig.get_setup_command('dials'),
                cwd=str(proc_dir),
                method=run_method,
                job_name=job_name,
                background=True,
                processors=self.kwargs.get("dials_nproc", 8),
                walltime="02:00:00",
                memory="16gb",
            )
            self.signals.result.emit(
                "SUBMITTED", f"Submitted DIALS SSX job '{job_name}'", self.master_file
            )

        except Exception as e:
            logger.error(f"DialsProcessDatasetWorker failed: {e}", exc_info=True)
            self.signals.error.emit(self.master_file, str(e))
            if "status_key" in locals():
                failed_status = {
                    "status": "FAILED",
                    "timestamp": time.time(),
                    "error": str(e),
                }
                self.redis_conn.set(
                    status_key, json.dumps(failed_status), ex=7 * 24 * 3600
                )
